  "inlineSchema": "// Prisma schema for ArabicMaster Pro\n// PostgreSQL database with NextAuth integration\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"./generated/prisma/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================\n// AUTHENTICATION MODELS (NextAuth)\n// ============================================\n\nmodel User {\n  id            String    @id @default(cuid())\n  email         String    @unique\n  emailVerified DateTime?\n  name          String?\n  image         String?\n  password      String? // For email/password auth (hashed with bcrypt)\n  role          Role      @default(USER)\n  banned        Boolean   @default(false)\n  banReason     String?\n  lastLogin     DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  // NextAuth relations\n  accounts Account[]\n  sessions Session[]\n\n  // App relations\n  progress     Progress[]\n  achievements UserAchievement[]\n  stats        UserStats?\n\n  @@map(\"users\")\n}\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n  @@map(\"verification_tokens\")\n}\n\n// ============================================\n// LEARNING PROGRESS MODELS\n// ============================================\n\nmodel Progress {\n  id            String    @id @default(cuid())\n  userId        String\n  phaseId       Int\n  lessonId      String\n  exerciseId    String?\n  completed     Boolean   @default(false)\n  score         Int? // Score 0-100\n  timeSpent     Int? // Time spent in seconds\n  attempts      Int       @default(0)\n  lastAttemptAt DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, lessonId, exerciseId])\n  @@index([userId, phaseId])\n  @@index([userId, lessonId])\n  @@map(\"progress\")\n}\n\n// ============================================\n// GAMIFICATION MODELS\n// ============================================\n\nmodel UserStats {\n  id                 String    @id @default(cuid())\n  userId             String    @unique\n  xp                 Int       @default(0)\n  level              Int       @default(1)\n  streak             Int       @default(0)\n  longestStreak      Int       @default(0)\n  lastActiveDate     DateTime?\n  totalTimeSpent     Int       @default(0) // Total time in seconds\n  lessonsCompleted   Int       @default(0)\n  exercisesCompleted Int       @default(0)\n  perfectScores      Int       @default(0)\n  wordsLearned       Int       @default(0)\n  createdAt          DateTime  @default(now())\n  updatedAt          DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"user_stats\")\n}\n\nmodel UserAchievement {\n  id            String   @id @default(cuid())\n  userId        String\n  achievementId String\n  unlockedAt    DateTime @default(now())\n  notified      Boolean  @default(false)\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, achievementId])\n  @@map(\"user_achievements\")\n}\n\n// ============================================\n// CONTENT MODELS (for admin management)\n// ============================================\n\nmodel Lesson {\n  id          String   @id @default(cuid())\n  phaseId     Int\n  order       Int\n  slug        String   @unique\n  titleEn     String\n  titleFr     String\n  titleAr     String\n  descEn      String?  @db.Text\n  descFr      String?  @db.Text\n  descAr      String?  @db.Text\n  duration    Int      @default(30) // Estimated duration in minutes\n  isPublished Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  exercises Exercise[]\n\n  @@index([phaseId, order])\n  @@map(\"lessons\")\n}\n\nmodel Exercise {\n  id            String       @id @default(cuid())\n  lessonId      String\n  order         Int\n  type          ExerciseType\n  difficulty    Difficulty\n  questionEn    String       @db.Text\n  questionFr    String       @db.Text\n  questionAr    String?      @db.Text\n  options       Json? // For multiple choice\n  correctAnswer String       @db.Text\n  explanationEn String?      @db.Text\n  explanationFr String?      @db.Text\n  explanationAr String?      @db.Text\n  audioText     String?      @db.Text // Text for TTS\n  isAIGenerated Boolean      @default(false)\n  createdAt     DateTime     @default(now())\n  updatedAt     DateTime     @updatedAt\n\n  lesson Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  @@index([lessonId, order])\n  @@map(\"exercises\")\n}\n\n// ============================================\n// ENUMS\n// ============================================\n\nenum Role {\n  USER\n  ADMIN\n}\n\nenum ExerciseType {\n  MULTIPLE_CHOICE\n  WRITING\n  LISTENING\n  ORAL\n  MATCHING\n  FILL_BLANK\n  TRANSLATION\n}\n\nenum Difficulty {\n  EASY\n  MEDIUM\n  HARD\n}\n",
